const https = require('https');
const query = $json.body.query || $json.body.kwargs || 'n8n news';
const apiKey = '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';
const data = JSON.stringify({api_key: apiKey, query: query, search_depth: 'advanced', include_answer: true});
const options = {hostname: 'api.tavily.com', port: 443, path: '/search', method: 'POST', headers: {'Content-Type': 'application/json', 'Content-Length': data.length}};
return new Promise((resolve) => {
  const req = https.request(options, (res) => {
    let body = '';
    res.on('data', (d) => body += d);
    res.on('end', () => { try { resolve([{ json: JSON.parse(body) }]); } catch (e) { resolve([{ json: { error: 'Parse Error', raw: body } }]); } });
  });
  req.on('error', (e) => resolve([{ json: { error: e.message } }]));
  req.write(data);
  req.end();
});
